#include <mutex>
#include <memory>
#include <print>

// Pattern 1: Meyers Singleton (C++11+ — local static is thread-safe)
class MeyersSingleton {
public:
    static MeyersSingleton& instance() {
        static MeyersSingleton inst; // Guaranteed initialized once, thread-safe
        return inst;
    }

    void do_work() { std::println("Meyers singleton working"); }

private:
    MeyersSingleton() = default;
    MeyersSingleton(const MeyersSingleton&) = delete;
    MeyersSingleton& operator=(const MeyersSingleton&) = delete;
};

// Pattern 2: call_once with unique_ptr (useful when you need pointer semantics
// or deferred initialization with external dependencies)
class ConfigurableSingleton {
    int config_;
    explicit ConfigurableSingleton(int cfg) : config_(cfg) {}

    static std::unique_ptr<ConfigurableSingleton> inst_;
    static std::once_flag flag_;

public:
    static ConfigurableSingleton& instance(int cfg = 0) {
        std::call_once(flag_, [cfg]{
            inst_ = std::make_unique<ConfigurableSingleton>(cfg);
        });
        return *inst_;
    }

    int config() const { return config_; }
};

std::unique_ptr<ConfigurableSingleton> ConfigurableSingleton::inst_;
std::once_flag ConfigurableSingleton::flag_;

int main() {
    // Meyers: simple, preferred in most cases
    MeyersSingleton::instance().do_work();

    // call_once: first call with cfg=42 wins
    auto& c1 = ConfigurableSingleton::instance(42);
    auto& c2 = ConfigurableSingleton::instance(99); // ignored
    std::println("Config: {}", c1.config()); // 42
    std::println("Same? {}", &c1 == &c2);   // true
}
```

**Why Meyers wins:** The C++11 standard mandates that local static initialization is thread-safe (§6.7). Zero overhead, no mutex, no raw pointer. Use it unless you need the singleton to be explicitly destroyable or configurable at first call.

**Pitfall:** Avoid the pre-C++11 double-checked locking pattern with raw pointers — it was broken without fences. The above patterns are correct and simpler.

