#include <future>
#include <thread>
#include <stdexcept>
#include <print>

// Basic promise/future value transfer
void compute(std::promise<int> prom, int x) {
    try {
        if (x < 0)
            throw std::invalid_argument("negative input");
        prom.set_value(x * x);
    } catch (...) {
        prom.set_exception(std::current_exception()); // propagate to future
    }
}

int main() {
    // --- Happy path ---
    std::promise<int> p1;
    std::future<int> f1 = p1.get_future();
    std::thread t1(compute, std::move(p1), 7);
    std::println("7^2 = {}", f1.get());
    t1.join();

    // --- Exception propagation ---
    std::promise<int> p2;
    std::future<int> f2 = p2.get_future();
    std::thread t2(compute, std::move(p2), -1);
    t2.join();
    try {
        f2.get(); // rethrows stored exception
    } catch (const std::exception& e) {
        std::println("Caught: {}", e.what()); // "negative input"
    }

    // --- shared_future: broadcast one result to many waiters ---
    std::promise<std::string> p3;
    std::shared_future<std::string> sf = p3.get_future().share();

    auto reader = [sf]{ // copyable
        std::println("Got: {}", sf.get());
    };

    std::thread t3(reader), t4(reader);
    p3.set_value("hello");
    t3.join(); t4.join();
}
```

**Key behaviors:**
- `promise::set_value` / `set_exception` can only be called **once** — second call throws `std::future_error`.
- `future::get()` can also be called only once; use `shared_future` for multiple consumers.
- If a promise is destroyed without `set_value/exception`, the future receives `broken_promise` exception.
- Exception propagates across thread boundaries transparently — no manual error codes needed.

