        return std::format("[{}:{}] {}", loc_.file_name(), loc_.line(), what());
    }
};

// Derived domain errors
struct NetworkError : AppError { using AppError::AppError; };
struct TimeoutError : NetworkError { using NetworkError::NetworkError; };
struct DatabaseError : AppError {
    int sql_code;
    DatabaseError(std::string msg, int code,
                  std::source_location loc = std::source_location::current())
        : AppError(std::move(msg), loc), sql_code(code) {}
};

// Exception chaining via std::nested_exception
void inner_op() {
    throw DatabaseError("Connection refused", 1045);
}

void middle_layer() {
    try {
        inner_op();
    } catch (...) {
        std::throw_with_nested( // wraps current_exception inside new one
            NetworkError("Failed to reach database tier")
        );
    }
}

void print_exception_chain(const std::exception& e, int depth = 0) {
    std::println("{}{}", std::string(depth * 2, ' '), e.what());
    try {
        std::rethrow_if_nested(e);
    } catch (const std::exception& inner) {
        print_exception_chain(inner, depth + 1);
    }
}

int main() {
    try {
        middle_layer();
    } catch (const AppError& e) {
        std::println("Caught at {}:{}", e.where().file_name(), e.where().line());
        print_exception_chain(e);
    }
}
