#include <exception>
#include <stdexcept>
#include <print>
#include <execinfo.h>
#include <cstdlib>

void my_terminate_handler() {
    std::println(stderr, "=== TERMINATE CALLED ===");

    // Print backtrace (Linux/glibc)
    void* frames[64];
    int n = backtrace(frames, 64);
    char** syms = backtrace_symbols(frames, n);
    for (int i = 0; i < n; ++i)
        std::println(stderr, "  {}", syms[i]);
    free(syms);

    // Inspect the current exception if any
    if (auto eptr = std::current_exception()) {
        try {
            std::rethrow_exception(eptr);
        } catch (const std::exception& e) {
            std::println(stderr, "Uncaught: {}", e.what());
        } catch (...) {
            std::println(stderr, "Uncaught unknown exception");
        }
    }
    std::abort();
}

void safe_init() {
    std::set_terminate(my_terminate_handler);
}

// noexcept violation triggers terminate
void must_not_throw() noexcept {
    throw std::runtime_error("oops"); // calls our handler
}

int main() {
    safe_init();
    try {
        throw std::runtime_error("handled normally");
    } catch (const std::exception& e) {
        std::println("Caught: {}", e.what());
    }
    // must_not_throw(); // uncomment to trigger terminate
}
```

**When terminate is called:**
- A `noexcept` function throws.
- An exception is thrown during stack unwinding.
- `std::terminate()` called directly.
- Destructor throws while another exception is active.

**Handler rules:**
- Must be `[[noreturn]]` — call `abort()` or `exit()`.
- Use `std::current_exception()` to inspect what went wrong.
- In production: flush logs to a file (stdout may be closed), generate a minidump, then `abort()` for core dump.
- `backtrace_symbols` is NOT async-signal-safe — only use in terminate handlers, not signal handlers.

```cpp
#include <memory_resource>
#include <vector>
#include <string>
#include <print>

struct ASTNode {
    std::pmr::string text;
    std::pmr::vector<ASTNode*> children;
    int kind;

    ASTNode(std::pmr::memory_resource* mr, std::string_view t, int k)
        : text(t, mr), children(mr), kind(k) {}
};

class Parser {
    std::array<std::byte, 1024 * 1024> arena_buf_; // 1MB stack buffer
    std::pmr::monotonic_buffer_resource arena_;
    std::pmr::unsynchronized_pool_resource pool_;

public:
    Parser()
        : arena_(arena_buf_.data(), arena_buf_.size())
        , pool_(&arena_) {}

    ASTNode* make_node(std::string_view text, int kind) {
        void* mem = pool_.allocate(sizeof(ASTNode), alignof(ASTNode));
        return new (mem) ASTNode(&pool_, text, kind);
    }

    ASTNode* parse_expr(std::string_view src) {
        auto* root = make_node(src, 0);
        root->children.push_back(make_node("lhs", 1));
        root->children.push_back(make_node("rhs", 1));
        return root;
    }
    // All nodes freed atomically when Parser destructs
};

void demo_pmr_policies() {
    // Stack arena: no heap allocations
    std::byte buf[4096];
    std::pmr::monotonic_buffer_resource local_arena(buf, sizeof(buf));
    std::pmr::vector<int> local_vec(&local_arena);
    for (int i = 0; i < 100; ++i) local_vec.push_back(i);

    // Null resource: throws on any allocation (useful for testing)
    std::pmr::vector<int> fixed(std::pmr::null_memory_resource());
    try { fixed.push_back(1); }
    catch (std::bad_alloc&) { std::println("Correctly rejected"); }
}

int main() {
    Parser p;
    auto* tree = p.parse_expr("a + b");
    std::println("Root: '{}', {} children", tree->text, tree->children.size());
    demo_pmr_policies();
}
```

**PMR resource chain:**
- `monotonic_buffer_resource` — bump allocator, O(1) alloc, bulk-free only.
- `unsynchronized_pool_resource` — fixed-size blocks on top of another resource.
- `synchronized_pool_resource` — thread-safe (adds mutex).
- Chain them: pool → monotonic → system for parser/compiler use cases.

```cpp
#include <system_error>
#include <expected>
#include <stdexcept>
#include <print>
#include <cerrno>

// Layer 1: C API returns errno
int c_read(const char* path, char* buf, int len) {
    errno = ENOENT; return -1;
}

// Layer 2: C++ wrapper — errno to error_code
std::error_code read_to_ec(const char* path, char* buf, int len) {
    if (c_read(path, buf, len) == -1)
        return std::error_code(errno, std::system_category());
    return {};
}

// Layer 3: expected — error_code to expected
std::expected<std::string, std::error_code>
read_to_expected(const char* path) {
    char buf[1024];
    auto ec = read_to_ec(path, buf, sizeof(buf));
    if (ec) return std::unexpected(ec);
    return std::string(buf);
}

// Layer 4: exception — expected to exception
std::string read_or_throw(const char* path) {
    auto result = read_to_expected(path);
    if (!result)
        throw std::system_error(result.error(), path);
    return *result;
}

// Boundary: exception back to expected (noexcept boundary)
std::expected<std::string, std::string>
noexcept_read(const char* path) noexcept {
    try {
        return read_or_throw(path);
    } catch (const std::exception& e) {
        return std::unexpected(e.what());
    }
}

int main() {
    auto ec = read_to_ec("/no/such/file", nullptr, 0);
    if (ec) std::println("EC: {} ({})", ec.message(), ec.value());

    auto exp = read_to_expected("/no/such/file");
    if (!exp) std::println("Expected: {}", exp.error().message());

    try { read_or_throw("/no/such/file"); }
    catch (const std::system_error& e) {
        std::println("Exception: {}", e.what());
    }

    auto safe = noexcept_read("/no/such/file");
    if (!safe) std::println("Noexcept: {}", safe.error());
}
```

**Conversion patterns:**
- C errno to `error_code`: `std::error_code(errno, std::system_category())`
- `error_code` to exception: `throw std::system_error(ec, context)`
- Exception to `expected`: try/catch returning `unexpected`
- `expected` to exception: check + throw on error

**Boundary guideline:** Choose ONE error mechanism per layer. Convert only at boundaries. Never mix exception + error_code returns in the same function.

```cpp
#include <memory>
#include <cstdio>
#include <print>

// Pattern 1: Lambda deleter
auto open_file(const char* path) {
    return std::unique_ptr<FILE, decltype([](FILE* f){ if(f) std::fclose(f); })>(
        std::fopen(path, "r"));
}

// Pattern 2: Stateless functor — zero overhead (EBO applies)
struct FreeDeleter {
    void operator()(void* p) const noexcept { std::free(p); }
};
using MallocPtr = std::unique_ptr<void, FreeDeleter>;

// Pattern 3: Non-pointer handle (file descriptor)
struct FdDeleter {
    using pointer = int; // unique_ptr uses this as the handle type
    void operator()(int fd) const noexcept {
        if (fd != -1) ::close(fd);
    }
};
using UniqueFd = std::unique_ptr<int, FdDeleter>;

// Pattern 4: Pool deallocator
template<typename Pool>
struct PoolDeleter {
    Pool* pool;
    template<typename T>
    void operator()(T* p) const noexcept {
        p->~T();
        pool->deallocate(p);
    }
};

void demonstrate() {
    // File RAII
    auto f = open_file("/etc/hostname");
    if (f) {
        char buf[128];
        std::fgets(buf, sizeof(buf), f.get());
        std::println("Hostname: {}", buf);
    } // fclose() called automatically

    // Malloc RAII
    MallocPtr mem(std::malloc(1024));
    // free() when mem goes out of scope

    // FD RAII
    UniqueFd fd(::open("/dev/null", O_RDONLY));
    if (fd.get() != -1)
        std::println("FD {} open", fd.get());
    // close() called automatically

    // Transfer ownership
    FILE* raw = f.release(); // f no longer owns it
    std::fclose(raw);
}

int main() { demonstrate(); }
```

**Size notes:**
- Stateless functor / lambda: `unique_ptr` = same size as raw pointer (Empty Base Optimization).
- Function pointer: `unique_ptr` = 2 pointers.
- Stateful lambda/closure: `unique_ptr` = pointer + closure state.

Prefer stateless functors for zero-overhead custom deletion. The `pointer` typedef trick (Pattern 3) lets `unique_ptr` manage non-pointer integer handles cleanly.

```cpp
#include <atomic>
#include <thread>
#include <print>
#include <chrono>

// C++20: atomic::wait() blocks without busy-polling (uses futex on Linux)
// atomic::notify_one/all() wakes blocked threads

// --- Basic event flag ---
class AtomicEvent {
    std::atomic<bool> flag_{false};
public:
    void signal() noexcept {
        flag_.store(true, std::memory_order_release);
        flag_.notify_all();
    }
    void wait() noexcept {
        flag_.wait(false, std::memory_order_acquire);
    }
    void reset() noexcept {
        flag_.store(false, std::memory_order_relaxed);
    }
};

// --- Value-change notification ---
std::atomic<int> phase{0};

void pipeline_demo() {
    std::jthread stage1([&]{
        std::this_thread::sleep_for(std::chrono::milliseconds(50));
        phase.store(1, std::memory_order_release);
        phase.notify_all();
        std::println("Stage 1 done");
    });

    std::jthread stage2([&]{
        phase.wait(0); // blocks until phase != 0
        std::println("Stage 2 starting (phase={})", phase.load());
        std::this_thread::sleep_for(std::chrono::milliseconds(30));
        phase.store(2, std::memory_order_release);
        phase.notify_all();
    });

    std::jthread stage3([&]{
        // Wait for phase >= 2
        int cur = phase.load(std::memory_order_acquire);
        while (cur < 2) {
            phase.wait(cur); // wakes on any change
            cur = phase.load(std::memory_order_acquire);
        }
        std::println("Stage 3: all phases done");
    });
}

int main() {
    // Simple producer-consumer with atomic wait
    std::atomic<int> data_ready{0};
    int data = 0;

    std::jthread producer([&]{
        data = 42;
        data_ready.store(1, std::memory_order_release);
        data_ready.notify_one();
    });

    std::jthread consumer([&]{
        data_ready.wait(0); // no busy-poll
        std::println("Got data: {}", data); // 42
    });

    producer.join(); consumer.join();
    pipeline_demo();
}
```

**atomic::wait vs condition_variable:**
- Simpler: no mutex, no predicate lambda, no spurious wakeup loop needed.
- `wait(old_val)` sleeps only if `*this == old_val` at check time — avoids TOCTOU.
- Uses `futex(FUTEX_WAIT)` on Linux — efficient kernel-level blocking.
- **Limitation:** Can only wait on a single atomic value equality. For arbitrary predicates or multiple conditions, use `condition_variable_any`.

```cpp
#include <stdexcept>
#include <system_error>
#include <print>

// Rule 1: Catch by const reference — avoids copy and object slicing
struct Derived : std::runtime_error {
    using std::runtime_error::runtime_error;
};

void good_catch() {
    try { throw Derived("derived error"); }
    catch (const Derived& e) { std::println("Derived: {}", e.what()); } // first
    catch (const std::runtime_error& e) { std::println("Base: {}", e.what()); }
    catch (const std::exception& e) { std::println("std: {}", e.what()); }
    catch (...) { std::println("unknown"); } // last resort
}

// Rule 2: catch(...) only at boundaries — always log, often rethrow
void boundary_handler() {
    try {
        throw std::runtime_error("deep error");
    } catch (...) {
        // Log the exception
        try { throw; }
        catch (const std::exception& e) { std::println("Log: {}", e.what()); }
        catch (...) { std::println("Log: unknown exception"); }
        throw; // re-propagate — don't swallow!
    }
}

// Rule 3: Don't use exceptions for control flow in hot paths
// BAD: std::stoi throws on invalid — expensive for expected failures
void parse_bad(const std::string& s) {
    try { int v = std::stoi(s); }
    catch (const std::invalid_argument&) {} // silently ignore
}

// GOOD: use std::from_chars — no exception, no allocation
#include <charconv>
bool parse_good(std::string_view s, int& out) {
    auto [ptr, ec] = std::from_chars(s.data(), s.data()+s.size(), out);
    return ec == std::errc{};
}

// Rule 4: Never swallow silently
void terrible() {
    try { throw std::runtime_error("bug"); }
    catch (...) {} // NEVER: hides bugs, impossible to debug
}

int main() {
    good_catch();
    try { boundary_handler(); } catch (...) {}

    int v;
    if (parse_good("42", v))
        std::println("Parsed: {}", v);
}
```

**Checklist:**
- Catch by `const T&`, never by value (no copy, no slice).
- Most-derived first, most-base last, `catch(...)` final.
- `catch(...)` at thread roots, `main`, and C callbacks — log + rethrow or abort.
- Never silently swallow. At minimum: `std::println(stderr, ...)`.
- Use `std::from_chars` / `std::expected` for expected parse failures instead of try-catch.

```cpp
#include <cstddef>
#include <vector>
#include <chrono>
#include <print>

// __restrict__: tells compiler these pointers don't alias.
// Without it, the compiler assumes a[i] and c[i] may overlap
// and cannot safely reorder or vectorize the loop.

void add_naive(const float* a, const float* b,
               float* c, std::size_t n) {
    for (std::size_t i = 0; i < n; ++i)
        c[i] = a[i] + b[i]; // may not vectorize without restrict
}

void add_fast(const float* __restrict__ a,
              const float* __restrict__ b,
              float*       __restrict__ c, std::size_t n) {
    // No aliasing: compiler emits SIMD (AVX/SSE) automatically
    for (std::size_t i = 0; i < n; ++i)
        c[i] = a[i] + b[i];
}

// Pragma hints for GCC/Clang
void scale(float* __restrict__ data, float factor, std::size_t n) {
    #pragma GCC ivdep               // ignore assumed vector dependencies
    #pragma clang loop vectorize(enable)
    for (std::size_t i = 0; i < n; ++i)
        data[i] *= factor;
}

// C++20: std::assume_aligned — stronger hint
void aligned_sum(const float* p, std::size_t n, float& out) {
    const float* aligned = std::assume_aligned<32>(p); // 32B = AVX
    float sum = 0.0f;
    for (std::size_t i = 0; i < n; ++i)
        sum += aligned[i];
    out = sum;
}

int main() {
    constexpr std::size_t N = 10'000'000;
    std::vector<float> a(N, 1.5f), b(N, 2.5f), c(N);

    auto bench = [&](auto fn, const char* label) {
        auto t0 = std::chrono::high_resolution_clock::now();
        for (int r = 0; r < 5; ++r) fn(a.data(), b.data(), c.data(), N);
        auto ms = std::chrono::duration_cast<std::chrono::milliseconds>(
            std::chrono::high_resolution_clock::now() - t0).count();
        std::println("{}: {}ms", label, ms);
    };

    bench(add_naive, "naive (no restrict)");
    bench(add_fast,  "fast  (restrict)  ");
    // Verify: g++ -O3 -march=native -S file.cpp | grep ymm
}
```

**Vectorization blockers to fix:**
- **Pointer aliasing:** add `__restrict__` or `std::assume_aligned`.
- **Non-unit stride:** restructure to sequential access (SoA layout).
- **Branches:** convert to branchless (ternary, min/max intrinsics).
- **Virtual calls:** devirtualize or separate dispatch from computation.

**Verify:** `-fopt-info-vec-optimized` (GCC) or `-Rpass=loop-vectorize` (Clang). Look for `ymm`/`zmm` registers in assembly output.

```cpp
#include <sys/mman.h>
#include <sys/stat.h>
#include <fcntl.h>
#include <semaphore.h>
#include <unistd.h>
#include <cstring>
#include <print>

struct SharedData {
    sem_t  ready;      // signaled by producer
    sem_t  consumed;   // signaled by consumer
    int    value;
    char   message[256];
};

constexpr const char* SHM = "/demo_shm";
constexpr std::size_t SZ  = sizeof(SharedData);

void producer() {
    int fd = ::shm_open(SHM, O_CREAT | O_RDWR, S_IRUSR | S_IWUSR);
    ::ftruncate(fd, SZ);
    auto* d = static_cast<SharedData*>(
        ::mmap(nullptr, SZ, PROT_READ|PROT_WRITE, MAP_SHARED, fd, 0));
    ::close(fd);

    // pshared=1: semaphores work across processes
    ::sem_init(&d->ready,    1, 0);
    ::sem_init(&d->consumed, 1, 0);

    for (int i = 0; i < 5; ++i) {
        d->value = i * 10;
        std::snprintf(d->message, sizeof(d->message),
                     "msg %d from pid %d", i, getpid());
        ::sem_post(&d->ready);    // signal consumer
        ::sem_wait(&d->consumed); // wait for ack
        std::println("Producer sent {}", i);
    }

    ::sem_destroy(&d->ready);
    ::sem_destroy(&d->consumed);
    ::munmap(d, SZ);
    ::shm_unlink(SHM);
}

void consumer() {
    int fd = ::shm_open(SHM, O_RDWR, 0);
    auto* d = static_cast<SharedData*>(
        ::mmap(nullptr, SZ, PROT_READ|PROT_WRITE, MAP_SHARED, fd, 0));
    ::close(fd);

    for (int i = 0; i < 5; ++i) {
        ::sem_wait(&d->ready);
        std::println("Consumer: val={} msg='{}'", d->value, d->message);
        ::sem_post(&d->consumed);
    }
    ::munmap(d, SZ);
}

int main(int argc, char** argv) {
    if (argc > 1 && std::string_view(argv[1]) == "consumer")
        consumer();
    else
        producer();
}
```

**Run:**
```bash
./shm_demo &
./shm_demo consumer
```

**Key points:**
- `shm_open` + `mmap(MAP_SHARED)`: both processes see the same physical pages — zero copy.
- `sem_init(..., pshared=1, ...)`: POSIX semaphore in shared memory, works across processes. Named semaphores (`sem_open`) are an alternative.
- Cleanup: `shm_unlink` removes the name entry; memory released when all mappings are closed.
- For higher throughput: use a lock-free ring buffer in shared memory — eliminate semaphore overhead for bulk transfers.

```cpp
#include <atomic>
#include <array>
#include <optional>
#include <cstddef>
#include <thread>
#include <print>

// SPSC (single-producer, single-consumer) ring buffer.
// head_ owned by producer (no sharing), tail_ owned by consumer.
// Zero CAS needed — just release/acquire pairs on the two counters.

template<typename T, std::size_t Cap>
class SPSCQueue {
    static_assert((Cap & (Cap-1)) == 0, "Cap must be power of two");
    static constexpr std::size_t MASK = Cap - 1;

    alignas(64) std::atomic<std::size_t> head_{0}; // written by producer
    alignas(64) std::atomic<std::size_t> tail_{0}; // written by consumer

    std::array<T, Cap> buf_;

public:
    bool try_push(T val) {
        std::size_t h = head_.load(std::memory_order_relaxed);
        std::size_t t = tail_.load(std::memory_order_acquire);
        if (h - t >= Cap) return false; // full
        buf_[h & MASK] = std::move(val);
        head_.store(h + 1, std::memory_order_release);
        return true;
    }

    std::optional<T> try_pop() {
        std::size_t t = tail_.load(std::memory_order_relaxed);
        std::size_t h = head_.load(std::memory_order_acquire);
        if (h == t) return std::nullopt; // empty
        T val = std::move(buf_[t & MASK]);
        tail_.store(t + 1, std::memory_order_release);
        return val;
    }

    bool empty() const {
        return head_.load(std::memory_order_acquire) ==
               tail_.load(std::memory_order_acquire);
    }
};

int main() {
    SPSCQueue<int, 1024> q;
    constexpr int N = 100'000;

    std::jthread producer([&]{
        int sent = 0;
        while (sent < N) {
            if (q.try_push(sent)) ++sent;
            else std::this_thread::yield();
        }
    });

    std::jthread consumer([&]{
        int recv = 0;
        while (recv < N) {
            if (auto v = q.try_pop()) ++recv;
            else std::this_thread::yield();
        }
        std::println("Consumed {} items", recv);
    });
}
```

**Why SPSC is fastest:**
- `head_`: written only by producer, read-only for consumer — no false sharing with `alignas(64)`.
- `tail_`: written only by consumer, read-only for producer — same.
- Only 2 atomic ops per push/pop (1 relaxed load + 1 release store).
- Throughput: ~500-800M ops/sec on modern x86 vs ~50M for mutex-based queue.

**Modular arithmetic:** Using unsigned `size_t` counters that wrap naturally — `h & MASK` maps to array index. Counter difference `h - t` gives queue size correctly even after wrap.

```cpp
#include <mutex>
#include <chrono>
#include <thread>
#include <source_location>
#include <print>

using namespace std::chrono_literals;

// Timed lock guard: throws if lock can't be acquired within timeout
class DeadlockGuard {
    std::timed_mutex& mu_;
    bool locked_;
public:
    explicit DeadlockGuard(
        std::timed_mutex& mu,
        std::chrono::milliseconds timeout = 5000ms,
        std::source_location loc = std::source_location::current())
        : mu_(mu)
    {
        locked_ = mu_.try_lock_for(timeout);
        if (!locked_)
            throw std::runtime_error(
                std::format("Lock timeout ({}ms) at {}:{}",
                    timeout.count(), loc.file_name(), loc.line()));
    }
    ~DeadlockGuard() { if (locked_) mu_.unlock(); }
    DeadlockGuard(const DeadlockGuard&) = delete;
};

std::timed_mutex mu_a, mu_b;

// Classic deadlock setup — detected via timeout
void thread_a() {
    try {
        DeadlockGuard g1(mu_a, 500ms);
        std::println("A: acquired mu_a, waiting for mu_b...");
        std::this_thread::sleep_for(100ms);

        DeadlockGuard g2(mu_b, 500ms); // times out — B holds mu_b
        std::println("A: acquired both (should not reach here in deadlock)");
    } catch (const std::exception& e) {
        std::println("A detected: {}", e.what());
        // Recovery: log, release A's lock (RAII handles it), retry after backoff
    }
}

void thread_b() {
    try {
        DeadlockGuard g1(mu_b, 500ms);
        std::println("B: acquired mu_b, waiting for mu_a...");
        std::this_thread::sleep_for(100ms);

        DeadlockGuard g2(mu_a, 500ms); // times out
    } catch (const std::exception& e) {
        std::println("B detected: {}", e.what());
    }
}

// The real fix: use scoped_lock — deadlock-free by design
void fixed() {
    std::scoped_lock lock(mu_a, mu_b); // acquires both atomically
    std::println("Fixed: both locks held safely");
}

int main() {
    std::jthread ta(thread_a);
    std::this_thread::sleep_for(50ms);
    std::jthread tb(thread_b);
    ta.join(); tb.join();

    fixed();
}
```

**When to use timed_mutex:**
- Diagnosing: wrap all locks with 5s timeout in debug builds — find hangs fast.
- Real-time systems: must not block indefinitely.
- Recovery: bounded wait + exponential backoff retry.

**Production pattern:** On timeout, log the lock holder (requires extra bookkeeping), dump the call stack, then abort the operation or retry. Never leave a server thread hung indefinitely on a mutex.

```cpp
#include <cstdlib>
#include <cstdio>
#include <new>
#include <atomic>
#include <print>

namespace alloc {
    std::atomic<std::size_t> live_bytes{0};
    std::atomic<long>        net_count{0};

    void report() {
        std::println("Live: {} bytes, net allocs: {}",
            live_bytes.load(), net_count.load());
    }
}

struct Header {
    std::size_t size;
    uint32_t magic;
    static constexpr uint32_t MAGIC = 0xDEADC0DE;
};

void* operator new(std::size_t sz) {
    void* raw = std::malloc(sz + sizeof(Header));
    if (!raw) throw std::bad_alloc();
    auto* h = static_cast<Header*>(raw);
    h->size  = sz;
    h->magic = Header::MAGIC;
    alloc::live_bytes.fetch_add(sz, std::memory_order_relaxed);
    alloc::net_count.fetch_add(1, std::memory_order_relaxed);
    return static_cast<char*>(raw) + sizeof(Header);
}

void operator delete(void* ptr) noexcept {
    if (!ptr) return;
    auto* raw = static_cast<char*>(ptr) - sizeof(Header);
    auto* h   = reinterpret_cast<Header*>(raw);
    if (h->magic != Header::MAGIC) {
        std::fputs("FATAL: heap corruption!\n", stderr);
        std::abort();
    }
    h->magic = 0; // detect double-free
    alloc::live_bytes.fetch_sub(h->size, std::memory_order_relaxed);
    alloc::net_count.fetch_sub(1, std::memory_order_relaxed);
    std::free(raw);
}

void operator delete(void* p, std::size_t) noexcept {
    ::operator delete(p);
}
void* operator new[](std::size_t sz) { return ::operator new(sz); }
void  operator delete[](void* p) noexcept { ::operator delete(p); }

int main() {
    {
        int* a = new int(42);
        auto* s = new std::string("hello");
        delete a;
        alloc::report(); // 1 live object (the string)
        delete s;
    }
    alloc::report(); // 0 live — no leaks
}
```

**Overhead:** sizeof(Header) = 8 bytes per allocation.

**Production alternatives:**
- `-fsanitize=address` (ASan): detects use-after-free, heap overflow, leaks. ~2x slowdown.
- `valgrind --leak-check=full`: no recompile needed, ~10-50x slowdown.
- This approach: zero false positives, tiny overhead, ships in production for monitoring.

**Magic canary:** detects double-free (second delete sees magic=0) and buffer overflow into the header (magic != MAGIC). Not a substitute for ASan but catches common bugs cheaply.

```cpp
#include <type_traits>
#include <string>
#include <concepts>
#include <print>
#include <vector>

// --- Concepts for detecting struct shape ---
template<typename T>
concept HasId = requires(const T& t) { { t.id } -> std::convertible_to<int>; };

template<typename T>
concept HasName = requires(const T& t) { { t.name } -> std::convertible_to<std::string>; };

template<typename T>
concept Iterable = requires(T t) {
    { t.begin() } -> std::input_or_output_iterator;
    { t.end() };
};

template<typename T>
concept Printable = requires(T t) { std::println("{}", t); };

// --- Generic serializer: branches at compile time ---
template<typename T>
std::string to_json(const T& v) {
    if constexpr (std::is_same_v<T, bool>) {
        return v ? "true" : "false";
    } else if constexpr (std::is_integral_v<T> || std::is_floating_point_v<T>) {
        return std::to_string(v);
    } else if constexpr (std::is_convertible_v<T, std::string_view>) {
        return '"' + std::string(v) + '"';
    } else if constexpr (Iterable<T>) {
        std::string s = "[";
        bool first = true;
        for (const auto& item : v) {
            if (!first) s += ',';
            s += to_json(item);
            first = false;
        }
        return s + "]";
    } else {
        // Struct: emit known fields
        std::string s = "{";
        bool first = true;
        auto emit = [&](std::string_view key, auto val) {
            if (!first) s += ',';
            s += '"' + std::string(key) + "\":" + to_json(val);
            first = false;
        };
        if constexpr (HasId<T>)   emit("id",   v.id);
        if constexpr (HasName<T>) emit("name", std::string(v.name));
        if constexpr (requires { v.value; }) emit("value", v.value);
        return s + '}';
    }
}

// --- Concept-constrained functions ---
template<HasId T>
void log_entity(const T& e) {
    std::println("Entity id={}", e.id);
    if constexpr (HasName<T>)
        std::println("  name={}", e.name);
}

struct User { int id; std::string name; double value; };
struct Tag  { int id; };

int main() {
    User u{42, "Alice", 3.14};
    Tag  t{7};

    std::println("{}", to_json(u));
    std::println("{}", to_json(t));
    std::println("{}", to_json(std::vector<int>{1,2,3}));
    std::println("{}", to_json(true));
    std::println("{}", to_json(42));

    log_entity(u); // prints id + name
    log_entity(t); // prints id only (no name member)
}
```

**Techniques:**
- `requires` expressions: detect member existence and type at compile time.
- `if constexpr`: dead branches not instantiated — no runtime cost, no linker errors.
- Concept constraints on template parameters enforce requirements at the call site with clear error messages.

**Limitation:** Detecting struct field count for structured bindings requires explicit arity dispatch (try binding `auto [a,b]`, `auto [a,b,c]`, etc.). True reflection (P2996) is targeted for C++26.

```cpp
#include <exception>
#include <functional>
#include <print>

template<std::invocable F>
class [[nodiscard]] ScopeExit {
    F fn_;
    bool active_ = true;
public:
    explicit ScopeExit(F fn) : fn_(std::move(fn)) {}
    ~ScopeExit() noexcept { if (active_) fn_(); }
    void release() noexcept { active_ = false; } // cancel
    ScopeExit(ScopeExit&&) = delete;
};

// scope_fail: runs ONLY if exiting via exception
template<std::invocable F>
class [[nodiscard]] ScopeFail {
    F fn_;
    int exceptions_ = std::uncaught_exceptions();
public:
    explicit ScopeFail(F fn) : fn_(std::move(fn)) {}
    ~ScopeFail() noexcept {
        if (std::uncaught_exceptions() > exceptions_) fn_();
    }
};

// scope_success: runs ONLY if exiting normally
template<std::invocable F>
class [[nodiscard]] ScopeSuccess {
    F fn_;
    int exceptions_ = std::uncaught_exceptions();
public:
    explicit ScopeSuccess(F fn) : fn_(std::move(fn)) {}
    ~ScopeSuccess() { // may throw — only called on normal exit
        if (std::uncaught_exceptions() == exceptions_) fn_();
    }
};

template<typename F> auto on_exit(F f)    { return ScopeExit<F>(std::move(f)); }
template<typename F> auto on_fail(F f)    { return ScopeFail<F>(std::move(f)); }
template<typename F> auto on_success(F f) { return ScopeSuccess<F>(std::move(f)); }

void demo(bool throw_midway) {
    std::println("--- demo(throw={}) ---", throw_midway);
    auto always  = on_exit([]{    std::println("exit: always"); });
    auto fail    = on_fail([]{    std::println("fail: exception path"); });
    auto success = on_success([]{ std::println("success: normal path"); });
    if (throw_midway) throw std::runtime_error("midway");
    std::println("Normal path");
}

// Practical: transaction management
void transaction(bool succeed) {
    begin_txn();
    auto rollback = on_fail([]{ rollback_txn(); });
    auto commit   = on_success([]{ commit_txn(); });
    if (!succeed) throw std::runtime_error("tx failed");
}

int main() {
    try { demo(false); } catch (...) {}
    try { demo(true);  } catch (...) {}
}
```

**How it works:** `std::uncaught_exceptions()` (C++17) returns the count of active exceptions in flight. At scope entry we capture the count. If the count increased in the destructor, we're unwinding.

**Output:**
```
--- demo(throw=false) ---
Normal path
success: normal path
exit: always

--- demo(throw=true) ---
fail: exception path
exit: always
```

`[[nodiscard]]` ensures you can't accidentally drop the guard (i.e., `on_exit(fn);` without binding to a variable produces a warning).

```cpp
#include <sys/sendfile.h>
#include <sys/socket.h>
#include <fcntl.h>
#include <sys/stat.h>
#include <unistd.h>
#include <stdexcept>
#include <print>

// sendfile: DMA transfer from file fd → socket fd, stays in kernel.
// No userspace buffer — avoids 2 copies (file→user, user→socket).

void serve_file(int client_fd, const char* path) {
    int fd = ::open(path, O_RDONLY);
    if (fd == -1) throw std::system_error(errno, std::system_category());

    struct stat st;
    ::fstat(fd, &st);
    off_t offset    = 0;
    off_t remaining = st.st_size;

    while (remaining > 0) {
        // sendfile may send less than requested on signals/partial writes
        ssize_t sent = ::sendfile(client_fd, fd, &offset, remaining);
        if (sent == -1) {
            ::close(fd);
            throw std::system_error(errno, std::system_category());
        }
        remaining -= sent;
    }
    ::close(fd);
    std::println("Sent {} bytes", st.st_size);
}

// splice: zero-copy between two fds using a pipe as kernel buffer
void proxy(int src, int dst, std::size_t total) {
    int pfd[2];
    ::pipe(pfd);
    constexpr std::size_t CHUNK = 65536;

    while (total > 0) {
        std::size_t n = std::min(total, CHUNK);
        ssize_t r = ::splice(src, nullptr, pfd[1], nullptr,
                             n, SPLICE_F_MOVE | SPLICE_F_MORE);
        if (r <= 0) break;
        ssize_t w = ::splice(pfd[0], nullptr, dst, nullptr,
                             r, SPLICE_F_MOVE);
        if (w <= 0) break;
        total -= w;
    }
    ::close(pfd[0]); ::close(pfd[1]);
}

// TCP_CORK: coalesce header + file into one TCP segment
void cork_send(int sock, const char* header, int file_fd, off_t size) {
    int on = 1;
    ::setsockopt(sock, IPPROTO_TCP, TCP_CORK, &on, sizeof(on));
    ::write(sock, header, strlen(header)); // buffered
    off_t off = 0;
    ::sendfile(sock, file_fd, &off, size);  // appended to same segment
    int off2 = 0;
    ::setsockopt(sock, IPPROTO_TCP, TCP_CORK, &off2, sizeof(off2)); // flush
}

int main() {
    std::println("zero-copy I/O demo (requires sockets to test fully)");
}
```

**Data path comparison:**
- `read()` + `write()`: disk → kernel buf → user buf → kernel socket buf → NIC (4 copies).
- `sendfile()`: disk → kernel socket buf → NIC (2 copies, 1 with DMA gather).
- `splice()`: pipe as kernel staging area, 0 user-space involvement.

**When to use:** HTTP file servers (nginx uses sendfile by default), video streaming, log shipping. For small files (<4KB) the overhead of sendfile setup may exceed the copy savings — measure first.

```cpp
#include <atomic>
#include <memory>
#include <thread>
#include <print>

// C++20: std::atomic<std::shared_ptr<T>> — atomic load/store/CAS on shared_ptr
// Before C++20: std::atomic_load/store (deprecated) or a mutex.

struct Config {
    int timeout_ms;
    std::string endpoint;
    Config(int t, std::string e) : timeout_ms(t), endpoint(std::move(e)) {}
};

// Read-copy-update pattern: readers get atomic snapshot,
// writer atomically replaces the pointer.
class ConfigStore {
    std::atomic<std::shared_ptr<Config>> ptr_;
public:
    explicit ConfigStore(std::shared_ptr<Config> cfg)
        : ptr_(std::move(cfg)) {}

    // Readers: cheap atomic load — gets a refcounted snapshot
    std::shared_ptr<Config> load() const {
        return ptr_.load(std::memory_order_acquire);
    }

    // Writer: replace config atomically
    void update(std::shared_ptr<Config> cfg) {
        ptr_.store(std::move(cfg), std::memory_order_release);
    }

    // CAS: conditional update (optimistic concurrency)
    bool try_update(std::shared_ptr<Config>& expected,
                    std::shared_ptr<Config> desired) {
        return ptr_.compare_exchange_strong(
            expected, std::move(desired),
            std::memory_order_acq_rel,
            std::memory_order_acquire);
    }
};

int main() {
    auto init = std::make_shared<Config>(5000, "https://api.v1.com");
    ConfigStore store(init);

    // Multiple readers — no locking
    std::vector<std::jthread> readers;
    for (int i = 0; i < 4; ++i)
        readers.emplace_back([&]{
            for (int j = 0; j < 1000; ++j) {
                auto cfg = store.load();
                // cfg keeps Config alive even if store.update() runs now
                (void)cfg->timeout_ms;
            }
        });

    // Writer updates live config
    std::jthread writer([&]{
        for (int v = 1; v <= 10; ++v) {
            store.update(std::make_shared<Config>(
                1000 * v, "https://api.v" + std::to_string(v) + ".com"));
            std::this_thread::sleep_for(std::chrono::milliseconds(5));
        }
    });

    readers.clear();
    auto final_cfg = store.load();
    std::println("Final: {}ms {}", final_cfg->timeout_ms, final_cfg->endpoint);
}
```

**Key property:** When a reader calls `load()`, it gets a `shared_ptr` that keeps the Config alive. Even if the writer calls `update()` immediately after, the reader's snapshot remains valid until the `shared_ptr` is dropped.

**Implementation note:** `std::atomic<shared_ptr>` may use an internal lock (not always wait-free — check `is_always_lock_free`). For guaranteed wait-free updates, use `std::atomic<T*>` with manual reference counting (hazard pointers or epoch-based reclamation).

