void benchmark(const char* label, char* mem, std::size_t sz) {
    std::memset(mem, 0, sz); // warm pages
    auto t0 = std::chrono::high_resolution_clock::now();
    volatile long sum = 0;
    for (std::size_t i = 0; i < sz; i += 64) // cache-line stride
        sum += mem[i];
    auto ms = std::chrono::duration_cast<std::chrono::milliseconds>(
        std::chrono::high_resolution_clock::now() - t0).count();
    std::println("{}: {}ms (node {})", label, ms, memory_node_of(mem));
}

int main() {
    if (!numa_available()) {
        std::println("Single NUMA node (no topology difference)");
        return 0;
    }

    int nodes = numa_num_configured_nodes();
    std::println("NUMA nodes: {}, CPUs: {}",
        nodes, numa_num_configured_cpus());

    if (nodes < 2) { std::println("Need 2+ nodes to demo"); return 0; }

    // Pin this thread to CPU 0 (node 0)
    pin_to_core(0);
    int local_node  = 0;
    int remote_node = 1;
    constexpr std::size_t SZ = 256UL << 20; // 256MB

    char* local  = (char*)numa_alloc_onnode(SZ, local_node);
    char* remote = (char*)numa_alloc_onnode(SZ, remote_node);

    benchmark("local  (node 0)", local,  SZ);
    benchmark("remote (node 1)", remote, SZ);
    // Typical: local ~20ms, remote ~80ms for 256MB

    numa_free(local,  SZ);
    numa_free(remote, SZ);
}
```

**NUMA best practices:**
- Pin worker threads to cores with `pthread_setaffinity_np`.
- Allocate memory with `numa_alloc_onnode` or `numa_alloc_local` (allocates on the current thread's node).
- Create one thread pool per NUMA node and route work locally.
- Use `numactl --membind=0 --cpunodebind=0 ./program` for process-level binding without code changes.

**Check your topology:** `numactl --hardware` shows nodes, CPUs per node, and distance matrix.

```cpp
#include <vector>
#include <list>
#include <map>
#include <print>

// --- vector: invalidates all iterators on realloc; from-point on insert/erase ---
void vector_rules() {
    std::vector<int> v = {1,2,3,4,5};
    v.reserve(20); // prevent realloc
    auto it = v.begin() + 2; // points to 3

    v.push_back(6); // no realloc: it still valid
    v.insert(v.begin(), 0); // shifts from begin: it now points to 2, not 3
    // v.push_back without reserve may invalidate ALL iterators
}

// --- list: insert/erase NEVER invalidate other iterators ---
void list_rules() {
    std::list<int> l = {1,2,3,4,5};
    auto it = std::next(l.begin(), 2); // points to 3
    l.push_back(99);   // it still valid
    l.erase(l.begin()); // erases 1; it still points to 3
    std::println("list it: {}", *it); // 3 — guaranteed valid
}

// --- map/set: insert never invalidates; erase only invalidates erased ---
void map_rules() {
    std::map<int,int> m = {{1,10},{2,20},{3,30}};
    auto it = m.find(2);
    m.insert({4,40}); // it still valid
    m.erase(1);       // it (key=2) still valid
    std::println("map it: {}", it->second); // 20
}

// --- Exception-safe append: strong guarantee ---
template<typename T>
void append_strong(std::vector<T>& dst, const std::vector<T>& src) {
    // Build in a copy — if any T copy throws, dst is untouched
    std::vector<T> tmp(dst);
    tmp.reserve(dst.size() + src.size());
    for (const auto& x : src) tmp.push_back(x); // may throw
    dst = std::move(tmp); // noexcept commit
}

// --- Correct erase-while-iterate ---
void safe_erase() {
    std::vector<int> v = {1,2,3,4,5,6};
    // WRONG: erasing invalidates it, then ++it is UB
    // for (auto it = v.begin(); it != v.end(); ++it)
    //     if (*it % 2 == 0) v.erase(it);

    // CORRECT: capture returned (valid) iterator
    for (auto it = v.begin(); it != v.end(); )
        it = (*it % 2 == 0) ? v.erase(it) : ++it;

    // C++20: erase_if (preferred)
    std::erase_if(v, [](int x){ return x % 2 == 0; });
}

int main() {
    vector_rules(); list_rules(); map_rules(); safe_erase();
}
```

**Invalidation table:**
| Container | Insert | Erase |
|---|---|---|
| `vector` | All if realloc; from-point otherwise | From-point onward |
| `deque` | All if at ends; all otherwise | All |
| `list`/`forward_list` | None | Only erased |
| `map`/`set`/`multimap` | None | Only erased |
| `unordered_map` | All if rehash | Only erased |

```cpp
// ABI (Application Binary Interface): the binary contract between
// compiled translation units. Breaking ABI requires recompiling all users.

// ====== BREAKS ABI ======

// 1. Adding a non-static data member (changes sizeof and field offsets)
class Widget_v1 { int x_; };            // sizeof = 4
class Widget_v2 { int x_; int y_; };    // sizeof = 8 — ABI break

// 2. Inserting virtual functions before existing ones (shifts vtable indices)
class Base_v1 {
public:
    virtual void foo() {} // vtable[0]
    virtual void bar() {} // vtable[1]
};
class Base_v2 {
public:
    virtual void baz() {} // inserted at [0] — ABI break: foo now at [1]
    virtual void foo() {}
    virtual void bar() {}
};

// 3. Changing function signatures, calling convention, or linkage

// ====== ABI-STABLE TECHNIQUES ======

// Technique 1: Pimpl — hide all implementation details
class StableWidget {
public:
    StableWidget();
    ~StableWidget();
    void do_work();
private:
    struct Impl;                      // forward-declared
    std::unique_ptr<Impl> impl_;      // only pointer in ABI
};
// Impl is in .cpp — change freely without breaking ABI

// Technique 2: Append-only virtual functions
class ExtendableBase {
public:
    virtual ~ExtendableBase() = default;
    virtual void method_v1() = 0;
    virtual void method_v2() {} // v2: APPEND — never insert before existing
};

// Technique 3: C linkage for maximum portability
extern "C" {
    struct Handle;                            // opaque type
    Handle* widget_create();
    void    widget_destroy(Handle*);
    int     widget_get_value(Handle*);
}

// Technique 4: Inline versioning namespace
namespace mylib {
    inline namespace v2 { // default
        struct Foo { void method_v2(); };
    }
    namespace v1 { // legacy
        struct Foo { void method_v1(); };
    }
}
// mylib::Foo -> v2. mylib::v1::Foo -> legacy.
```

**Vtable layout (Itanium ABI, GCC/Clang):**
```
[ offset-to-top | RTTI pointer | vfunc[0] | vfunc[1] | ... ]
```
Virtual functions indexed by **declaration order**. Inserting before existing functions shifts all indices — incompatible with callers compiled against old ABI.

**ABI evolution rules:**
1. Add members only via Pimpl.
2. Add virtual functions only at the end.
3. Use `[[deprecated]]` before removing.
4. Version shared libraries with SONAME (`libfoo.so.2`).
5. Use `nm -D` and `abi-compliance-checker` to detect breaks automatically.

```cpp
#include <cstdio>
#include <cstdlib>
#include <fcntl.h>
#include <unistd.h>
#include <print>

// __attribute__((cleanup(fn))): GCC/Clang extension.
// Calls fn(&var) when var goes out of scope — C-style RAII.
// Works in C and C++. Not available on MSVC.

// C-style cleanup functions
void close_file(FILE** fp) {
    if (*fp) { std::fclose(*fp); *fp = nullptr; }
}
void free_mem(void** p) {
    std::free(*p); *p = nullptr;
}
void close_fd(int* fd) {
    if (*fd >= 0) { ::close(*fd); *fd = -1; }
}

void c_style_demo() {
    FILE* f __attribute__((cleanup(close_file))) =
        std::fopen("/etc/hostname", "r");
    void* buf __attribute__((cleanup(free_mem))) =
        std::malloc(256);
    int fd __attribute__((cleanup(close_fd))) =
        ::open("/dev/null", O_RDONLY);

    if (!f || !buf || fd < 0) return; // cleanup runs on early return

    char* cbuf = static_cast<char*>(buf);
    std::fgets(cbuf, 256, f);
    std::println("Hostname: {}", cbuf);
    // f, buf, fd all cleaned up here automatically
}

// C++ equivalent — prefer in C++ code
#include <memory>
void cpp_style_demo() {
    auto f = std::unique_ptr<FILE, decltype(&std::fclose)>(
        std::fopen("/etc/hostname", "r"), std::fclose);
    auto buf = std::make_unique<char[]>(256);

    if (!f || !buf) return;
    std::fgets(buf.get(), 256, f.get());
    std::println("Hostname (C++): {}", buf.get());
}

// Mixed: C header with cleanup, called from C++
extern "C" {
    typedef struct { int fd; } CHandle;
    void destroy_handle(CHandle** h) {
        if (*h && (*h)->fd >= 0) {
            ::close((*h)->fd); (*h)->fd = -1;
        }
    }
    CHandle* acquire_handle() {
        CHandle* h = (CHandle*)malloc(sizeof(CHandle));
        h->fd = ::open("/dev/null", O_RDONLY);
        return h;
    }
}

void mixed_demo() {
    CHandle* h __attribute__((cleanup(destroy_handle))) = acquire_handle();
    std::println("FD: {}", h ? h->fd : -1);
}

int main() {
    c_style_demo();
    cpp_style_demo();
    mixed_demo();
}
```

**When __attribute__((cleanup)) is appropriate:**
- Pure C code needing RAII-like behavior (kernel modules, embedded, C99 code).
- Headers shared between C and C++ (use `#ifdef __cplusplus` to select RAII style).
- Quick resource safety in Linux system programming without full C++ RAII classes.

**Lifetime:** Variables cleaned up in reverse declaration order within the scope — same as C++ destructors. Does NOT call when exit() is used; only on scope exit.
